sql:
SELECT AVG(budget) AS average_budget
FROM movies
WHERE revenue > 1000000000;

SELECT budget
FROM movies
WHERE movie_id = 1;

external_knowledge:
- "treasure chests" refers to genres that are rich in revenue;
- "number of films they hold" refers to the count of movies in each genre;
- "average wealth" corresponds to the average revenue of movies in a genre;
- "total riches accumulated" refers to the sum of revenues for all movies in a genre;
- "greatest hoard of gold" means the total revenue in descending order.

sql:
